lessons.description:
Erstelle benannte Animationen mit <kbd>@keyframes</kbd> und wende sie mit der <kbd>animation</kbd> Kurzschreibweise an.<br><br><pre>@keyframes bounce {
  50% { transform: translateY(-20px); }
}
.ball {
  animation: bounce 1s infinite;
}</pre>

lessons.solution:
animation-name: pulse;
animation-duration: 2s;
animation-delay: 1s;
animation-iteration-count: 2;
animation-fill-mode: forwards;
